INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a878a07d-ccf8-464e-8571-1f9637c3ec8b',
  '00000000-0000-0000-0000-000000000001',
  $escape$PyTorch Custom Modules — Building Reusable Layers with nn.Module$escape$,
  $escape$Every learnable component in PyTorch inherits from `nn.Module`. When you subclass it, you get parameter tracking, `.to(device)`, `.train()`/`.eval()` toggling, and `state_dict()` serialization for free. Define learnable weights in `__init__` using `nn.Parameter` or registered submodules — never as plain tensors, or they'll be invisible to the optimizer. The `forward()` method describes the computation graph; backprop is handled automatically via autograd.

For activation functions, prefer `F.gelu` or `F.silu` over `F.relu` in modern transformer-style architectures — they're smooth and empirically stronger. Use `nn.Sequential` for linear stacks, but reach for a custom module the moment you need residual connections, gating, or conditional logic.

A practical pattern: wrap your normalization + activation + dropout into a single `Block` module. This keeps `forward()` readable, lets you swap internals cleanly, and makes the block reusable across encoder/decoder stacks. Call `self.apply(init_weights)` in `__init__` to initialize all child modules recursively without touching each layer manually.$escape$,
  $escape$import torch
import torch.nn as nn
import torch.nn.functional as F

class FeedForwardBlock(nn.Module):
    def __init__(self, d_model: int, expansion: int = 4, dropout: float = 0.1):
        super().__init__()
        self.fc1 = nn.Linear(d_model, d_model * expansion)
        self.fc2 = nn.Linear(d_model * expansion, d_model)
        self.norm = nn.LayerNorm(d_model)
        self.drop = nn.Dropout(dropout)
        self.apply(self._init_weights)

    def _init_weights(self, m):
        if isinstance(m, nn.Linear):
            nn.init.xavier_uniform_(m.weight)
            nn.init.zeros_(m.bias)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        residual = x
        x = self.norm(x)
        x = self.drop(F.gelu(self.fc1(x)))
        return residual + self.fc2(x)$escape$,
  $escape$python$escape$,
