INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9529eae3-8a75-4bd7-b7a3-7c6ce8f3d483',
  '00000000-0000-0000-0000-000000000001',
  $escape$PyTorch Optimizers — SGD, Adam, AdamW, and LR Schedulers Explained$escape$,
  $escape$PyTorch ships all major optimizers in `torch.optim`. `SGD` with `momentum=0.9` and `weight_decay` is still competitive for vision tasks but sensitive to learning rate. `Adam` uses adaptive per-parameter learning rates via first and second moment estimates (`betas=(0.9, 0.999)`), making it forgiving — but its L2 regularization via `weight_decay` is broken: it decouples incorrectly because decay is applied to the gradient, not the weight. `AdamW` fixes this by applying weight decay directly to parameters, decoupled from the gradient update — prefer it over `Adam` for transformers and fine-tuning. Pair any optimizer with a scheduler. `CosineAnnealingLR` is the default choice for most training runs. `OneCycleLR` enables super-convergence in fewer epochs. Always call `scheduler.step()` after `optimizer.step()`. Use `torch.optim.lr_scheduler.get_last_lr()` to log the current LR. For mixed-precision training with `torch.amp`, gradient scaling with `GradScaler` must wrap the backward pass before `optimizer.step()`.$escape$,
  $escape$import torch
import torch.nn as nn
from torch.optim import AdamW
from torch.optim.lr_scheduler import CosineAnnealingLR

model = nn.Linear(128, 10)
optimizer = AdamW(model.parameters(), lr=1e-3, weight_decay=0.01, betas=(0.9, 0.999))
scheduler = CosineAnnealingLR(optimizer, T_max=100, eta_min=1e-6)

for epoch in range(100):
    loss = compute_loss(model)  # your training step
    optimizer.zero_grad()
    loss.backward()
    torch.nn.utils.clip_grad_norm_(model.parameters(), max_norm=1.0)
    optimizer.step()
    scheduler.step()
    print(f"Epoch {epoch} | LR: {scheduler.get_last_lr()[0]:.2e}")$escape$,
  $escape$python$escape$,
