INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5047b97c-8130-4d56-9a46-4865428a4400',
  '00000000-0000-0000-0000-000000000001',
  $escape$PyTorch Production Readiness — ONNX Export, TorchScript, and Serving$escape$,
  $escape$Shipping a PyTorch model to production means choosing between three export paths: TorchScript, ONNX, or torch.export (the new dynamo-based path in 2.x). TorchScript via torch.jit.trace works well for static graphs but silently ignores Python control flow — use torch.jit.script for models with branches. For cross-runtime serving (ONNX Runtime, TensorRT, CoreML), torch.onnx.export is the standard, but watch for opset mismatches: most production runtimes target opset 17 or 18. Always pass dynamic_axes for variable batch/sequence sizes or your model will be hardcoded to the traced input shape. Post-export, validate outputs with numpy allclose against the original model — quantization and op fusion can introduce float drift. For high-throughput REST serving, torchserve handles model versioning, batching, and metrics out of the box. If latency is critical, compile with torch.compile(model, backend='onnxrt') to fuse ops before export. Never serve a raw .pth weights file — it requires the original class definition at load time, creating a fragile coupling.$escape$,
  $escape$import torch
import torch.onnx
import numpy as np
import onnxruntime as ort

model = MyModel().eval()
dummy = torch.randn(1, 3, 224, 224)

torch.onnx.export(
    model, dummy, "model.onnx",
    opset_version=18,
    input_names=["input"],
    output_names=["output"],
    dynamic_axes={"input": {0: "batch_size"}, "output": {0: "batch_size"}}
)

session = ort.InferenceSession("model.onnx", providers=["CUDAExecutionProvider"])
onnx_out = session.run(None, {"input": dummy.numpy()})[0]

with torch.no_grad():
    torch_out = model(dummy).numpy()

assert np.allclose(torch_out, onnx_out, atol=1e-5), "Output mismatch — check opset or quantization"$escape$,
  $escape$python$escape$,
